INIT_ASM = """
.BANK 0 SLOT 0
.ORG $0000

    di
    im 1
    jp   RESET

.ORG $0038
    jp   INT_Handler

.ORG $0066
    jp   NMI_Handler

.ORG $0070
RESET:
    ld   sp, $DFF0
    call VDP_Init
    call PSG_Init
    call ClearVRAM
    ld   a, 2
    ld   ($FFFF), a
    call LoadPalettes
    call LoadTilemap
    call LoadSAT
    ld   a, 3
    ld   ($FFFF), a
    call LoadTiles
    ld   a, 1
    ld   b, %11100000
    call VDP_WriteReg
    ei
    jp   GameMain
"""

INTERRUPTS_ASM = """
.BANK 0 SLOT 0
.ORG $0038
INT_Handler:
    push af
    push bc
    push de
    push hl
    in   a, ($BF)
    pop hl
    pop de
    pop bc
    pop af
    ei
    reti

.ORG $0066
NMI_Handler:
    retn
"""

