HAL_VDP_ASM = """
.BANK 0 SLOT 0
.ORG $0000

.define VDP_DATA_PORT   $BE
.define VDP_CTRL_PORT   $BF

VDP_Init:
    ld   a, 0
    ld   b, %00000000
    call VDP_WriteReg
    ld   a, 1
    ld   b, %00000000
    call VDP_WriteReg
    ld   a, 2
    ld   b, %11000000
    call VDP_WriteReg
    ld   a, 5
    ld   b, %11111110
    call VDP_WriteReg
    ret

VDP_WriteReg:
    ld   c, VDP_CTRL_PORT
    ld   a, %10000000
    or   a
    out  (c), a
    ld   a, b
    out  (c), a
    ret

VDP_SetWriteAddress:
    ld   a, l
    ld   c, VDP_CTRL_PORT
    out  (c), a
    ld   a, h
    or   $40
    out  (c), a
    ret

VDP_WriteData:
    ld   c, VDP_DATA_PORT
    out  (c), a
    ret

ClearVRAM:
    ld   hl, $0000
    call VDP_SetWriteAddress
    ld   bc, $4000
    ld   a, 0
clear_loop:
    ld   c, VDP_DATA_PORT
    out  (c), a
    dec  bc
    ld   a, b
    or   c
    jr   nz, clear_loop
    ret
"""

HAL_PSG_ASM = """
.BANK 0 SLOT 0
.ORG $0000

PSG_Init:
    ld   a, %10011111
    out  ($7F), a
    ld   a, %10111111
    out  ($7F), a
    ld   a, %11011111
    out  ($7F), a
    ld   a, %11111111
    out  ($7F), a
    ret

PSG_SetTone:
    push af
    push bc
    ld   c, $7F
    ld   b, a
    and  $0F
    out  (c), a
    ld   a, h
    and  $03
    rlca
    rlca
    rlca
    rlca
    or   b
    and  $7F
    out  (c), a
    pop bc
    pop af
    ret

PSG_SetVolume:
    ld   c, $7F
    push af
    ld   a, %10000000
    rlca
    rlca
    rlca
    rlca
    and  $7F
    or   b
    and  $9F
    out  (c), a
    pop af
    ret
"""

HAL_INPUT_ASM = """
.BANK 0 SLOT 0
.ORG $0000

.define BTN_UP      %00000001
.define BTN_DOWN    %00000010
.define BTN_LEFT    %00000100
.define BTN_RIGHT   %00001000
.define BTN_1       %00010000
.define BTN_2       %00100000

Input_Init:
    ret

Input_ReadP1:
    in   a, ($DC)
    and  $3F
    cpl
    ret

Input_ReadP2:
    in   a, ($DD)
    and  $3F
    cpl
    ret
"""

HAL_MAPPER_ASM = """
.BANK 0 SLOT 0
.ORG $0000

Mapper_Init:
    xor  a
    ld   ($FFFC), a
    ld   ($FFFD), a
    inc  a
    ld   ($FFFE), a
    inc  a
    ld   ($FFFF), a
    ret

Mapper_SetBank:
    ld   hl, $FFFD
    add  a, l
    ld   l, a
    ld   (hl), b
    ret
"""

