MAKEFILE_CONTENT = """# WLA-DX Makefile for SMS project
# Generated by nes2sms

ifeq ($(OS),Windows_NT)
    CC = wla-z80.exe
    LD = wlalink.exe
    RM = del /Q
else
    CC = wla-z80
    LD = wlalink
    RM = rm -f
endif

CFLAGS = -v

OBJECTS = main.o init.o interrupts.o assets.o \\
          hal/vdp.o hal/psg.o hal/input.o hal/mapper.o \\
          stubs/game_logic.o

all: game.sms

%.o: %.asm
\t$(CC) $(CFLAGS) $<

game.sms: $(OBJECTS) link.sms
\t$(LD) link.sms $@

clean:
\t$(RM) *.o hal\\*.o stubs\\*.o game.sms 2>nul || $(RM) *.o hal/*.o stubs/*.o game.sms

.PHONY: all clean
"""

LINKER_SCRIPT = """[libraries]

[objects]
main.o
"""
